  ('islands-6f0ba476-moex-00064', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列何種情形得暫緩移送強制執行？', '["納稅義務人於繳納期間屆滿後，主張經濟困難但未依法申請復查", "納稅義務人請求分期繳納，稅捐機關尚未核准", "納稅義務人提起訴願即可申請暫緩移送強制執行", "納稅義務人對復查決定之應納稅額繳納三分之一，並依法提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00065', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依現行房地合一課稅規定，下列敘述何者錯誤？①甲於111年購買土地，113年與建商合作興建', '["乙於111年購買預售屋，113年交屋前轉售契約者，視 為房地交易，應課徵房地合一稅", "丙於112年參與都市更新，114年完工後持有1年出售，應 按20%稅率課稅", "丁於112年購屋供自住，113年出售，可依自住房屋土地規定適用400萬元 免稅優惠", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00066', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法之規定，下列敘述何者正確？①外銷貨物及與外銷有關之勞務，均', '["銷售土地、醫療勞務及教育勞務，均屬零稅率項目", "銷售金條、金幣及純金飾 品，其加工費部分仍屬免稅", "農民銷售其收穫之農產品及副產物，免徵營業稅  ⑤保稅區營業 人銷售貨物予課稅區營業人供直接出口者，適用零稅率", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00067', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '甲公司為一般營業人，經稽徵機關查得其辦理營業登記時，申報資料部分錯誤，且變更營業地址 後未依規定申請變更登記，經通知限期改正後仍未補辦。依營業稅法規定，下列敘述何者正確？', '["構成漏稅行為，應按漏稅額處五倍以下罰鍰", "僅屬遲延登記，補辦後可免予處罰", "應按未開立統一發票之銷售額處百分之一罰鍰", "得通知限期改正或補辦，並處新臺幣1,500元以上15,000元以下罰鍰；屆期仍未改正者，得按 次處罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00068', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依據加值型及非加值型營業稅法與其施行細則，有關營業稅免稅與零稅率的敘述，下列敘述何者', '["零稅率表示銷售貨物或勞務所適用的營業稅率為零，由於銷項稅額為零，如有溢付稅額， 由主管稽徵機關查明後全數退還", "免稅等同於零稅率", "免稅，在銷售階段免徵營業稅，但進 項稅額不能扣抵或退還", "保稅區營業人銷售與課稅區營業人存入物流中心以供外銷之貨物適 用零稅率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00069', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列何項進項稅額不得扣抵銷項稅額？①交際應酬用之', '["供員工年終摸彩之貨物", "勞軍用之貨物", "公司送貨用之小貨車  ⑤辦公室水電 費用  ⑥購買供總經理上下班使用的高級轎車", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00070', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '下列何者非屬應稅貨物，免徵貨物稅之情形？', '["經國防部核定直接供軍用之貨物", "參加展覽，並出售者", "用作製造另一應稅貨物之原料者", "運銷國外者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00071', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '林先生於民國114年5月20日死亡，遺有一筆房地，市價2,400萬元，其中土地公告現值1,200 萬元，房屋評定標準價格600萬元；其生前曾於112年10月10日贈與女兒現金300萬元，並於 111年7月1日贈與孫子價值200萬元之汽車一輛。試問林先生之遺產總額為多少？', '["1,800萬", "2,100萬", "2,400萬", "2,700萬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00072', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依據遺產及贈與稅法之規定，下列何者非屬不計入贈與總額的項目？', '["作農業使用之農業用地及其地上農作物，受贈人自受贈之日起五年內，未將該土地繼續作農業 使用且未在有關機關所令期限內恢復作農業使用", "捐贈各級政府之財產", "扶養義務人為受扶養人支付之生活費", "配偶相互贈與之財產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00073', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法關於贈與稅之申報與繳納程序，下列敘述何者錯誤？', '["贈與人在一年內贈與財產總額超過免稅額時，應於超過部分發生後30日內，向主管稽徵機關 辦理申報", "同一贈與人在同一年內有多次應申報之贈與行為者，應於最後一次辦理贈與稅申報時，將前次 贈與事實及納稅情形合併申報", "贈與稅應於稽徵機關送達核定納稅通知書之日起2個月內繳清，必要時可申請延期2個月", "贈與稅應納稅額在30萬元以上確有困難時，納稅義務人得申請分36期繳納，每期間隔不得超 過2個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
